<template><main class="container py-5"><h1>Khuyến mãi & Tin tức</h1><div v-if="message" class="alert" :class="ok?'alert-success':'alert-danger'">{{ message }}</div><div class="marketing-grid"><section class="cs-card p-4"><h2>Khuyến mãi</h2><form class="form-grid" @submit.prevent="savePromotion"><input v-model.trim="promotion.name" class="form-control" placeholder="Tên" required><input v-model.trim="promotion.code" class="form-control" placeholder="Mã" required><select v-model="promotion.type" class="form-select"><option value="PERCENT">Phần trăm</option><option value="FIXED">Số tiền</option></select><input v-model.number="promotion.value" class="form-control" type="number" min="1" placeholder="Giá trị" required><input v-model="promotion.startDate" class="form-control" type="date"><input v-model="promotion.endDate" class="form-control" type="date"><label><input v-model="promotion.status" type="checkbox"> Đang hoạt động</label><button class="btn btn-danger">{{ promotion.id?'Cập nhật':'Thêm' }}</button></form><div v-for="item in promotions" :key="item.id" class="admin-row"><span><strong>{{ item.name }}</strong><small>{{ item.code }} · {{ item.value }} {{ item.type==='PERCENT'?'%':'VNĐ' }}</small><span><input v-model.number="carIds[item.id]" class="form-control form-control-sm" type="number" min="1" placeholder="ID xe"><button class="btn btn-sm btn-outline-success" @click="applyPromotion(item.id)">Áp dụng</button></span></span><span><button class="btn btn-sm btn-outline-primary" @click="promotion={...item,startDate:dateInput(item.startDate),endDate:dateInput(item.endDate)}">Sửa</button><button class="btn btn-sm btn-outline-danger" @click="removePromotion(item.id)">Xóa</button></span></div></section><section class="cs-card p-4"><h2>Tin tức</h2><form class="form-grid" @submit.prevent="saveNews"><input v-model.trim="article.title" class="form-control" placeholder="Tiêu đề" required><input v-model.trim="article.slug" class="form-control" placeholder="Slug (có thể bỏ trống)"><input v-model.trim="article.thumbnail" class="form-control" placeholder="Ảnh"><textarea v-model.trim="article.summary" class="form-control" maxlength="500" placeholder="Tóm tắt"></textarea><textarea v-model.trim="article.content" class="form-control" rows="5" placeholder="Nội dung"></textarea><select v-model="article.status" class="form-select"><option value="DRAFT">Bản nháp</option><option value="PUBLISHED">Xuất bản</option></select><button class="btn btn-danger">{{ article.id?'Cập nhật':'Thêm' }}</button></form><div v-for="item in articles" :key="item.id" class="admin-row"><span><strong>{{ item.title }}</strong><small>{{ item.status }}</small></span><span><button class="btn btn-sm btn-outline-primary" @click="article={...item}">Sửa</button><button class="btn btn-sm btn-outline-danger" @click="removeNews(item.id)">Xóa</button></span></div></section></div></main></template>
<script setup>import{onMounted,ref}from'vue';import{promotionApi,newsApi}from'../../api';const promotions=ref([]),articles=ref([]),message=ref(''),ok=ref(true),carIds=ref({});const emptyPromotion=()=>({name:'',code:'',type:'PERCENT',value:null,startDate:'',endDate:'',status:true}),emptyNews=()=>({title:'',slug:'',thumbnail:'',summary:'',content:'',status:'DRAFT'});const promotion=ref(emptyPromotion()),article=ref(emptyNews());const dateInput=v=>v?String(v).slice(0,10):'';async function load(){const[p,n]=await Promise.all([promotionApi.getAll(),newsApi.getAll()]);promotions.value=p.data.data||[];articles.value=n.data.data||[]}async function action(fn,success){try{await fn();ok.value=true;message.value=success;await load()}catch(e){ok.value=false;message.value=e.response?.data?.message||'Không thể thực hiện'}}async function savePromotion(){await action(()=>promotion.value.id?promotionApi.update(promotion.value.id,promotion.value):promotionApi.create(promotion.value),'Đã lưu khuyến mãi');promotion.value=emptyPromotion()}async function removePromotion(id){if(confirm('Xóa khuyến mãi này?'))await action(()=>promotionApi.delete(id),'Đã xóa khuyến mãi')}async function applyPromotion(id){if(carIds.value[id])await action(()=>promotionApi.applyToCar(id,carIds.value[id]),'Đã áp dụng khuyến mãi cho xe')}async function saveNews(){await action(()=>article.value.id?newsApi.update(article.value.id,article.value):newsApi.create(article.value),'Đã lưu tin tức');article.value=emptyNews()}async function removeNews(id){if(confirm('Xóa tin tức này?'))await action(()=>newsApi.delete(id),'Đã xóa tin tức')}onMounted(load)</script>
<style scoped>.marketing-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px}.form-grid{display:grid;gap:10px;margin:20px 0}.admin-row{display:flex;justify-content:space-between;gap:12px;border-top:1px solid #e5e7eb;padding:13px 0}.admin-row span{display:flex;gap:6px}.admin-row span:first-child{flex-direction:column}.admin-row small{color:#6b7280}@media(max-width:900px){.marketing-grid{grid-template-columns:1fr}}</style>
